def get_brixton_road_landmarks():
    landmarks = [
        {
            "name": "Christ Church",
            "description": "A Neo-Byzantine style church opened in 1902, located at the north end of Brixton Road."
        },
        {
            "name": "Lambeth Town Hall",
            "description": "A municipal building housing local government offices, located near the former Brixton Oval."
        },
        {
            "name": "Ritzy Cinema",
            "description": "An independent cinema established in the early 20th century, situated in Brixton."
        },
        {
            "name": "Brixton Tate Library",
            "description": "A public library with a statue of Henry Tate outside, dedicated to arts and culture."
        },
        {
            "name": "St Matthew's Church",
            "description": "A church located at the junction of Brixton Road, Effra Road, and Brixton Hill."
        }
    ]
    return landmarks

# Example usage:
landmarks = get_brixton_road_landmarks()
for landmark in landmarks:
    print(f"{landmark['name']}: {landmark['description']}")
